export class Common{constructor(){this.data=[],this.noticesCount=null,this.recCourse=document.getElementById("recommended-courses-name"),this.otherCourse=document.getElementById("other-courses"),this.news=document.getElementById("news"),this.staff=document.getElementById("staff"),this.support=document.getElementById("support"),this.menu=document.querySelector(".menu"),this.menuOpenClose=document.querySelector(".menu-open-close"),this.init()}async init(){this.menuAction(),this.pageActions(),this.data=[{date:"10.03.2026",messages:[{time:"04:00",text:"А почему Магистр Йода не пошёл в аспирантуру?",important:!0},{time:"17:00",text:"Денег нет, но вы держитесь",important:!1}]},{date:"16.03.2026",messages:[{time:"13:37",text:"Ни что так не губит как к 11 туз",important:!1}]},{date:"05.04.2026",messages:[{time:"8:00",text:"14.04.26 - Собрание в 118 кабинете в 8:00",important:!0}]},{date:"24.04.2026",messages:[{time:"12:00",text:"В валик пойдёте?",important:!1}]}],this.notices()}notices(){this.data.forEach(t=>{t.messages.forEach(t=>{t.important&&this.noticesCount++})}),document.querySelectorAll(".notice-count").forEach(t=>{t.innerText=this.noticesCount})}pageActions(){this.recCourse.onclick=()=>{location.href="#/video/"},this.otherCourse.onclick=()=>{location.href="#/choice/"},this.news.onclick=()=>{location.href="#/news/"},this.staff.onclick=()=>{location.href="#/staff/"},this.support.onclick=()=>{location.href="#/support/"}}menuAction(){this.menuOpenClose.onclick=()=>{"block"===this.menu.style.display?this.menu.style.display="none":this.menu.style.display="block"}}}